1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Empty / processing fee
6	  it("empty item list — premium 5 G (only processing fee)", () => {
7	    const result = processScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // Base premiums for main items (no modifiers, 0 years, single item)
15	  it.todo("single sword — base premium 100 G + 10 G first insurance + 5 G fee = 115 G");
16	  it.todo("single amulet — base premium 60 G + 6 G first insurance + 5 G fee = 71 G");
17	  it.todo("single staff — base premium 80 G + 8 G first insurance + 5 G fee = 93 G");
18	  it.todo("single potion — base premium 40 G + 4 G first insurance + 5 G fee = 49 G");
19	
20	  // Components
21	  it.todo("single rune — base premium 25 G + first insurance and fee");
22	  it.todo("2 runes — base premium 50 G (no block)");
23	  it.todo("3 runes — base premium 60 G (building block applies)");
24	  it.todo("4 runes — base premium 100 G (no block — block requires exactly 3)");
25	  it.todo("7 runes — base premium 175 G (no block — not exactly 3)");
26	
27	  // Alike components clarification (❓ alike means same type)
28	  it.todo("2 runes + 1 moonstone — base premium 75 G (no block: different types)");
29	  it.todo("3 runes + 3 moonstones — base premium 120 G (two separate blocks)");
30	
31	  // Item-specific modifiers (in isolation)
32	  it.todo("cursed sword adds 50% risk surcharge (50 G to sword)");
33	  it.todo("highly enchanted sword (enchantment 5) adds 30% surcharge");
34	  it.todo("enchantment 4 does not trigger high-enchantment surcharge");
35	  it.todo("cursed AND highly enchanted sword stacks both surcharges");
36	
37	  // Policy-wide modifiers
38	  it.todo("long-standing customer (≥ 2 years) gets 20% loyalty discount");
39	  it.todo("customer with exactly 2 years gets loyalty discount");
40	  it.todo("first insurance adds 10% initial assessment surcharge per item");
41	  it.todo("follow-up contract gets 15% discount on the policy");
42	
43	  // Modifier scope (❓ cursed surcharge applies only to cursed item)
44	  it.todo("multi-item policy: cursed sword + plain amulet — premium with cursed surcharge applies to sword's base only");
45	
46	  // Integration examples from spec
47	  it.todo("newcomer with cursed sword (enchantment 3) — 165 G");
48	  it.todo("long-standing customer's second contract: cursed sword enchantment 7 — 160 G");
49	
50	  // Rounding
51	  it.todo("premium that yields 197.5 G — rounded up to 198 G");
52	
53	  // Claim — standard reimbursement
54	  it.todo("regular sword (steel, enchantment 3), damage 500 G — payout 400 G");
55	  it.todo("damage to a rune (insurance value 250 G), damage 200 G — payout 100 G");
56	
57	  // Claim — deductible per damage event
58	  it.todo("dragon attack damages sword (500 G) and amulet (300 G) — payout 600 G (deductible per item)");
59	
60	  // Claim — high enchantment clause
61	  it.todo("steel sword enchantment 9, damage 1000 G — payout 400 G (50% then deductible)");
62	
63	  // Claim — dragon material clause
64	  it.todo("dragon-material sword enchantment 5, damage 800 G — payout 700 G (full minus deductible)");
65	
66	  // Claim — both clauses apply, 50% wins
67	  it.todo("dragon-material sword enchantment 9, damage 1000 G — payout 400 G (50% wins, then deductible)");
68	  it.todo("dragon-material sword enchantment exactly 8, damage 1000 G — payout 400 G (high-enchantment wins)");
69	
70	  // Claim — cap exhaustion
71	  it.todo("sword and amulet policy — insurance sum 1600 G, cap 3200 G");
72	  it.todo("cursed sword — cap 2000 G (based on unmodified insurance value)");
73	  it.todo("sword + 3 runes — insurance sum 1750 G (block does not affect insurance sum)");
74	  it.todo("two successive claims of 1500 G on a sword — first payout 1400 G remaining 600 G, second payout 600 G remaining 0 G");
75	
76	  // Multiple items of same type
77	  it.todo("policy with two swords — insurance sum 2000 G");
78	  it.todo("two swords damaged in dragon attack — each entry has its own deductible");
79	  it.todo("damages contain more entries of a type than insured — CLI exits non-zero");
80	
81	  // Payout rounding (in MHPCO's favor: down)
82	  it.todo("payout that yields 350.5 G — rounded down to 350 G");
83	
84	  // Edge cases — error handling
85	  it.todo("quote with unknown item type — CLI exits non-zero, error to stderr");
86	  it.todo("claim references item not part of policy — CLI exits non-zero");
87	  it.todo("claim with negative damage amount — CLI exits non-zero");
88	
89	  // Multi-step scenarios
90	  it.todo("follow-up contracts: first quote no follow-up discount, second quote has follow-up discount");
91	});
